#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[49];
    float distance;
} Record;

void findLowest(Record *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int loadData(char *filename, Record *records, LatLong *locations, int maxRecords) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;
    char *data_folder = getenv("DATA_FOLDER");
    if (!data_folder) data_folder = ".";

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        return 0;
    }

    while (!feof(flist) && recNum < maxRecords) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            break;
        }
        snprintf(db_fullname, sizeof(db_fullname), "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            fclose(flist);
            return recNum;
        }

        while (!feof(fp) && recNum < maxRecords) {
            char line[50];
            if (fgets(line, sizeof(line), fp) == NULL) break;
            // Remove newline if present
            size_t len = strlen(line);
            if (len > 0 && line[len-1] == '\n') line[len-1] = '\0';

            strncpy(records[recNum].recString, line, 48);
            records[recNum].recString[48] = '\0';

            char substr[6];
            // Extract lat (positions 28-32 in original string, 0-indexed 28 to 32)
            // Original code: *(record.recString+i+28) for i=0..4
            int start_lat = 28;
            int start_lng = 33;

            for (i = 0; i < 5; i++) {
                if (start_lat + i < len) substr[i] = line[start_lat + i];
                else substr[i] = ' ';
            }
            substr[5] = '\0';
            locations[recNum].lat = atof(substr);

            for (i = 0; i < 5; i++) {
                if (start_lng + i < len) substr[i] = line[start_lng + i];
                else substr[i] = ' ';
            }
            substr[5] = '\0';
            locations[recNum].lng = atof(substr);

            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void compute_distances(LatLong *locations, float *distances, int numRecords, float lat, float lng) {
    #pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; globalId++) {
        float diff_lat = lat - locations[globalId].lat;
        float diff_lng = lng - locations[globalId].lng;
        distances[globalId] = (float)sqrt(diff_lat * diff_lat + diff_lng * diff_lng);
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    *r = 10;
    *lat = 0.0f;
    *lng = 0.0f;
    *q = 0;
    *t = 0;
    *p = -1;
    *d = -1;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    if (i < argc) *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        i++;
                        if (i < argc) *lat = atof(argv[i]);
                    } else {
                        i++;
                        if (i < argc) *lng = atof(argv[i]);
                    }
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    if (i < argc) *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    if (i < argc) *d = atoi(argv[i]);
                    break;
                case 'f':
                    i++;
                    if (i < argc) {
                        // Ignoring data_folder setting as we use env var or default
                    }
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

int main(int argc, char *argv[]) {
    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    // Allocate maximum possible records initially, or use a dynamic approach
    // For this translation, we'll assume a reasonable max or read twice. 
    // To mimic the vector behavior simply, we'll allocate a large buffer or read count first.
    // Since the original reads into vectors, let's allocate a large enough buffer for typical use
    // or implement a two-pass load. Given the constraints, let's try to load with a large cap.
    int maxRecords = 1000000; 
    Record *records = (Record *)malloc(sizeof(Record) * maxRecords);
    LatLong *locations = (LatLong *)malloc(sizeof(LatLong) * maxRecords);

    if (!records || !locations) {
        fprintf(stderr, "Memory allocation failed\n");
        return -1;
    }

    int numRecords = loadData(filename, records, locations, maxRecords);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    double init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
           d2h_time = 0, close_time = 0, total_time = 0;

    double start_total = omp_get_wtime();

    // Simulate init time
    double end_init = omp_get_wtime();
    init_time = (end_init - start_total) * 1000.0;

    double start_mem = omp_get_wtime();
    float *recordDistances = (float *)malloc(sizeof(float) * numRecords);
    double end_mem = omp_get_wtime();
    mem_alloc_time = (end_mem - start_mem) * 1000.0;

    double start_h2d = omp_get_wtime();
    // Data is already in 'locations' array (host memory), simulating transfer time if needed
    // In OpenMP, data is local, so transfer is negligible or zero, but we measure the block
    double end_h2d = omp_get_wtime();
    h2d_time = (end_h2d - start_h2d) * 1000.0;

    double start_kernel = omp_get_wtime();
    compute_distances(locations, recordDistances, numRecords, lat, lng);
    double end_kernel = omp_get_wtime();
    kernel_time = (end_kernel - start_kernel) * 1000.0;

    double start_d2h = omp_get_wtime();
    // Data is already in 'recordDistances' (host memory)
    double end_d2h = omp_get_wtime();
    d2h_time = (end_d2h - start_d2h) * 1000.0;

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet) {
        for (int i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    }

    double start_close = omp_get_wtime();
    free(recordDistances);
    free(records);
    free(locations);
    double end_close = omp_get_wtime();
    close_time = (end_close - start_close) * 1000.0;

    double end_total = omp_get_wtime();
    total_time = (end_total - start_total) * 1000.0;

    if (timing) {
        printf("# Records\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%d        \t%f [%.2fMB]\t%f\t%f [%.2fMB]\t%f\n\n",
               numRecords,
               h2d_time / 1000.0, (float)(sizeof(LatLong) * numRecords) / 1e6,
               kernel_time / 1000.0,
               d2h_time / 1000.0, (float)(sizeof(float) * numRecords) / 1e6,
               total_time / 1000.0);

        printf("Init: %f\n", init_time);
        printf("MemAlloc: %f\n", mem_alloc_time);
        printf("HtoD: %f\n", h2d_time);
        printf("Exec: %f\n", kernel_time);
        printf("DtoH: %f\n", d2h_time);
        printf("Close: %f\n", close_time);
        printf("Total: %f\n", total_time);
    }

    return 0;
}
